#include <stdio.h>
#define MOD 1000000007LL

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        long long A = 1; // A_0
        long long B = 0; // B_0
        for (int i = 0; i < N; ++i) {
            long long nextA = B % MOD;
            long long nextB = ( (long long)K * A + (long long)(K - 1) * B ) % MOD;
            A = nextA;
            B = nextB;
        }
        printf("%lld\n", A % MOD);
    }
    return 0;
}

